final:
module verified_LFSR_counter(
   input                clk ,
   input                rst_n,

   output reg [31:0]    obf_Q  
);
    always@(posedge clk or negedge rst_n) begin
        if (!rst_n) obf_Q <= 32'h1;
        else begin
            obf_Q <= {obf_Q[30:0], obf_Q[31] ^ obf_Q[30] ^ obf_Q[29] ^ obf_Q[9]};
        end
    end
endmodule
